{
  "schema": "brainflow.procedure.v1",
  "name": "llm_io_arglength_guardrail",
  "version": 1,
  "rules": [
    {
      "id": "prefer_file_payloads",
      "when": "invoking tools or subprocesses with large payloads",
      "do": "write payloads to a temp file and pass only the file path; keep CLI args short"
    },
    {
      "id": "cap_inline_text",
      "when": "building inline arguments",
      "do": "limit inline text to <= 1024 chars; otherwise switch to file path"
    }
  ]
}
